import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Eye, EyeOff, Mail, Lock, User, TrendingUp, Sparkles } from 'lucide-react';
import useAuthStore from '../store/authStore';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';

const floatingCards = [
  { icon: '≡ƒÆ│', label: 'Smart Budgets', top: '15%', left: '5%', delay: 0 },
  { icon: '≡ƒôê', label: '+24% Growth', top: '70%', left: '3%', delay: 0.4 },
  { icon: '≡ƒöö', label: 'Bill Reminders', top: '30%', right: '4%', delay: 0.8 },
  { icon: 'ΓÜí', label: 'Instant Insights', top: '65%', right: '5%', delay: 1.2 },
];

const FloatingCard = ({ card }) => (
  <motion.div
    initial={{ opacity: 0, y: 20 }}
    animate={{ opacity: 1, y: 0, transition: { delay: card.delay, duration: 0.6 } }}
    style={{ top: card.top, left: card.left, right: card.right }}
    className="absolute hidden lg:flex items-center gap-2 glass-card px-4 py-2 text-sm font-medium"
    style={{
      top: card.top, left: card.left, right: card.right,
      background: 'rgba(22,22,31,0.9)',
      border: '1px solid rgba(99,102,241,0.2)',
      borderRadius: '12px',
      padding: '10px 16px',
      display: 'flex',
      alignItems: 'center',
      gap: '8px',
      fontSize: '13px',
      fontWeight: '500',
      color: 'var(--text-primary)',
      backdropFilter: 'blur(10px)',
    }}
  >
    <span>{card.icon}</span>
    <span>{card.label}</span>
  </motion.div>
);

export default function AuthPage() {
  const [mode, setMode] = useState('login');
  const [showPass, setShowPass] = useState(false);
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const { login, register, isLoading } = useAuthStore();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    let result;
    if (mode === 'login') {
      result = await login(form.email, form.password);
    } else {
      if (!form.name) return toast.error('Name is required');
      result = await register(form.name, form.email, form.password);
    }
    if (result.success) {
      toast.success(mode === 'login' ? 'Welcome back! ≡ƒæï' : 'Account created! ≡ƒÄë');
      navigate('/');
    } else {
      toast.error(result.message);
    }
  };

  return (
    <div style={{ minHeight: '100vh', background: 'var(--bg-primary)', display: 'flex', alignItems: 'stretch', position: 'relative', overflow: 'hidden' }}>
      <div className="animated-bg" />

      {/* Left Panel */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', justifyContent: 'center', alignItems: 'center', padding: '60px', position: 'relative', overflow: 'hidden' }} className="hidden lg:flex">
        <div style={{ position: 'absolute', width: '600px', height: '600px', borderRadius: '50%', background: 'radial-gradient(circle, rgba(99,102,241,0.12) 0%, transparent 70%)', top: '50%', left: '50%', transform: 'translate(-50%,-50%)' }} />
        
        {floatingCards.map((card, i) => (
          <FloatingCard key={i} card={card} />
        ))}

        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          style={{ textAlign: 'center', zIndex: 1 }}
        >
          <div style={{ fontSize: '64px', marginBottom: '24px' }}>≡ƒÆ╣</div>
          <h1 className="gradient-text" style={{ fontSize: '42px', fontWeight: '800', fontFamily: 'Space Grotesk', lineHeight: '1.2', marginBottom: '16px' }}>
            FinTracker Pro
          </h1>
          <p style={{ color: 'var(--text-secondary)', fontSize: '18px', maxWidth: '360px', lineHeight: '1.6' }}>
            Your intelligent companion for financial freedom and subscription mastery.
          </p>

          {/* Stats row */}
          <div style={{ display: 'flex', gap: '24px', marginTop: '48px', justifyContent: 'center' }}>
            {[{ val: 'Γé╣2L+', label: 'Tracked Monthly' }, { val: '500+', label: 'Active Users' }, { val: '99.9%', label: 'Uptime' }].map((s, i) => (
              <motion.div key={i} initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.3 + i * 0.1 }}
                style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '24px', fontWeight: '800', color: 'var(--accent-light)' }}>{s.val}</div>
                <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '4px' }}>{s.label}</div>
              </motion.div>
            ))}
          </div>
        </motion.div>
      </div>

      {/* Right Panel - Auth Form */}
      <div style={{ width: '100%', maxWidth: '480px', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '40px 32px', borderLeft: '1px solid var(--border)', background: 'var(--bg-secondary)' }}>
        <motion.div
          initial={{ opacity: 0, x: 20 }}
          animate={{ opacity: 1, x: 0 }}
          transition={{ duration: 0.6 }}
          style={{ width: '100%', maxWidth: '380px' }}
        >
          {/* Logo mobile */}
          <div style={{ marginBottom: '32px', textAlign: 'center' }} className="lg:hidden">
            <span style={{ fontSize: '32px' }}>≡ƒÆ╣</span>
            <h1 className="gradient-text" style={{ fontSize: '24px', fontWeight: '800', fontFamily: 'Space Grotesk' }}>FinTracker Pro</h1>
          </div>

          <div style={{ marginBottom: '32px' }}>
            <h2 style={{ fontSize: '28px', fontWeight: '800', marginBottom: '8px', fontFamily: 'Space Grotesk' }}>
              {mode === 'login' ? 'Welcome back' : 'Create account'}
            </h2>
            <p style={{ color: 'var(--text-secondary)', fontSize: '14px' }}>
              {mode === 'login' ? 'Sign in to your FinTracker dashboard' : 'Start your financial journey today'}
            </p>
          </div>

          {/* Tab switcher */}
          <div style={{ display: 'flex', background: 'var(--bg-card)', borderRadius: '10px', padding: '4px', marginBottom: '28px', border: '1px solid var(--border)' }}>
            {['login', 'register'].map((m) => (
              <button key={m} onClick={() => setMode(m)} style={{
                flex: 1, padding: '8px 16px', borderRadius: '8px', border: 'none', cursor: 'pointer',
                fontSize: '14px', fontWeight: '500', transition: 'all 0.2s',
                background: mode === m ? 'linear-gradient(135deg, #6366f1, #8b5cf6)' : 'transparent',
                color: mode === m ? 'white' : 'var(--text-secondary)',
              }}>
                {m === 'login' ? 'Sign In' : 'Sign Up'}
              </button>
            ))}
          </div>

          <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
            <AnimatePresence>
              {mode === 'register' && (
                <motion.div key="name" initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} exit={{ opacity: 0, height: 0 }}>
                  <label style={{ display: 'block', fontSize: '13px', fontWeight: '500', color: 'var(--text-secondary)', marginBottom: '6px' }}>Full Name</label>
                  <div style={{ position: 'relative' }}>
                    <User size={16} style={{ position: 'absolute', left: '14px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
                    <input className="input-field" style={{ paddingLeft: '40px' }} placeholder="Ankit Mohanty" value={form.name}
                      onChange={(e) => setForm({ ...form, name: e.target.value })} />
                  </div>
                </motion.div>
              )}
            </AnimatePresence>

            <div>
              <label style={{ display: 'block', fontSize: '13px', fontWeight: '500', color: 'var(--text-secondary)', marginBottom: '6px' }}>Email Address</label>
              <div style={{ position: 'relative' }}>
                <Mail size={16} style={{ position: 'absolute', left: '14px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
                <input className="input-field" style={{ paddingLeft: '40px' }} type="email" placeholder="ankit@example.com" value={form.email}
                  onChange={(e) => setForm({ ...form, email: e.target.value })} required />
              </div>
            </div>

            <div>
              <label style={{ display: 'block', fontSize: '13px', fontWeight: '500', color: 'var(--text-secondary)', marginBottom: '6px' }}>Password</label>
              <div style={{ position: 'relative' }}>
                <Lock size={16} style={{ position: 'absolute', left: '14px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)' }} />
                <input className="input-field" style={{ paddingLeft: '40px', paddingRight: '44px' }} type={showPass ? 'text' : 'password'}
                  placeholder="ΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇóΓÇó" value={form.password} onChange={(e) => setForm({ ...form, password: e.target.value })} required minLength={6} />
                <button type="button" onClick={() => setShowPass(!showPass)} style={{ position: 'absolute', right: '14px', top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)' }}>
                  {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>

            <motion.button type="submit" className="btn-primary" disabled={isLoading}
              style={{ width: '100%', padding: '14px', fontSize: '15px', marginTop: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' }}
              whileTap={{ scale: 0.98 }}>
              {isLoading ? (
                <span className="spinner" style={{ width: '20px', height: '20px', borderWidth: '2px' }} />
              ) : (
                <>{mode === 'login' ? 'Sign In' : 'Create Account'} <Sparkles size={16} /></>
              )}
            </motion.button>
          </form>

          {mode === 'login' && (
            <div style={{ marginTop: '24px', padding: '16px', background: 'rgba(99,102,241,0.08)', borderRadius: '10px', border: '1px solid rgba(99,102,241,0.15)' }}>
              <p style={{ fontSize: '12px', color: 'var(--text-secondary)', marginBottom: '6px', fontWeight: '600' }}>≡ƒöæ Demo Credentials</p>
              <p style={{ fontSize: '12px', color: 'var(--text-muted)' }}>Email: demo@fintracker.com</p>
              <p style={{ fontSize: '12px', color: 'var(--text-muted)' }}>Password: demo123</p>
            </div>
          )}
        </motion.div>
      </div>
    </div>
  );
}
